"use client";

import React, { useState } from 'react';
import { BookingStep1 } from '../Booking/BookingStep1';
import { BookingStep2 } from '../Booking/BookingStep2';
import { BookingStep3 } from '../Booking/BookingStep3';
import { BookingSuccess } from '../Booking/BookingSuccess';
import { BookingState } from '../../../types';

export default function BookPage() {
    const [step, setStep] = useState(1);
    const [bookingData, setBookingData] = useState<BookingState>({
        serviceId: '',
        serviceName: '',
        city: ['Chennai'],
        date: '',
        time: '',
        patientName: '',
        patientAge: '',
        patientGender: '',
        guardianName: '',
        relationship: '',
        mobile: '',
        alternateMobile: '',
        address: '',
    });

    const updateData = (updates: Partial<BookingState>) => {
        setBookingData(prev => ({ ...prev, ...updates }));
    };

    const nextStep = () => setStep(prev => prev + 1);
    const prevStep = () => setStep(prev => prev - 1);

    return (
        <>
            {step === 1 && <BookingStep1 data={bookingData} updateData={updateData} onNext={nextStep} />}
            {step === 2 && <BookingStep2 data={bookingData} updateData={updateData} onNext={nextStep} onBack={prevStep} />}
            {step === 3 && <BookingStep3 data={bookingData} onConfirm={nextStep} onEdit={(s: number) => setStep(s)} />}
            {step === 4 && <BookingSuccess data={bookingData} />}
        </>
    );
}
